import { useState, useEffect, useCallback, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import API from "../../api";

export default function WaiterPanel() {
  const [tables, setTables] = useState([]);
  const [menu, setMenu] = useState([]);
  const [specials, setSpecials] = useState({});
  const [selectedTable, setSelectedTable] = useState(null);
  const [allRounds, setAllRounds] = useState([]);
  const [draftRoundIdx, setDraftRoundIdx] = useState(null);
  const [loading, setLoading] = useState(true);
  const [roundLoading, setRoundLoading] = useState(false);
  const [view, setView] = useState("tables");
  const [confirmModal, setConfirmModal] = useState(false);
  const [confirming, setConfirming] = useState(false);
  const [activeOrderType, setActiveOrderType] = useState("table");
  const [taxSettings, setTaxSettings] = useState(null);
  const { user, logout, theme, toggleTheme } = useAuth();
  const navigate = useNavigate();
  const summaryRef = useRef(null);

  const glass = {
    backdropFilter: "blur(14px)",
    background: "rgba(255,255,255,0.04)",
    border: "1px solid rgba(255,255,255,0.08)",
    boxShadow: "0 10px 30px rgba(0,0,0,0.25)",
  };

  const smooth = {
    transition: "all 0.25s cubic-bezier(.4,.2,.2,1)"
  };

  const loadData = useCallback(async () => {
    try {
      const [t, m, s, tax] = await Promise.all([
        API.get("/tables"),
        API.get("/menu"),
        API.get("/extras/specials"),
        API.get("/extras/tax-settings"),
      ]);
      setTables(t.data);
      setMenu(m.data.filter(i => i.is_available));
      const sMap = {};
      s.data.forEach(sp => {
        sMap[sp.menu_id] = {
          ...sp,
          discounted_price: sp.discount_pct > 0
            ? Math.round(sp.price * (1 - sp.discount_pct / 100))
            : sp.price,
        };
      });
      setSpecials(sMap);
      setTaxSettings(tax.data);
    } catch {}
    setLoading(false);
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const loadTableRounds = useCallback(async (table) => {
    setRoundLoading(true);
    try {
      const allOrdersRes = await API.get(`/orders/table/${table.id}/all`);
      const orders = allOrdersRes.data || [];

      if (orders.length === 0) {
        setAllRounds([]);
        setDraftRoundIdx(null);
        setRoundLoading(false);
        return;
      }

      const roundsWithItems = await Promise.all(
        orders.map(async (order, idx) => {
          try {
            const detail = await API.get(`/orders/${order.id}`);
            return {
              order: detail.data.order,
              items: detail.data.items || [],
              roundNumber: idx + 1,
            };
          } catch {
            return { order, items: [], roundNumber: idx + 1 };
          }
        })
      );

      setAllRounds(roundsWithItems);

      const draftIdx = roundsWithItems.findIndex(r => r.order.status === "draft");
      setDraftRoundIdx(draftIdx === -1 ? null : draftIdx);
    } catch {}
    setRoundLoading(false);
  }, []);

  const selectTable = async (table) => {
    setSelectedTable(table);
    setActiveOrderType("table");
    setView("order");
    await loadTableRounds(table);
  };

  const refreshRound = async (roundIdx) => {
    const round = allRounds[roundIdx];
    if (!round) return;
    try {
      const detail = await API.get(`/orders/${round.order.id}`);
      setAllRounds(prev => {
        const updated = [...prev];
        updated[roundIdx] = {
          ...updated[roundIdx],
          order: detail.data.order,
          items: detail.data.items || [],
        };
        return updated;
      });
    } catch {}
  };

  const startOrder = async () => {
    if (!selectedTable) return;
    setRoundLoading(true);
    try {
      const res = await API.post("/orders", { table_id: selectedTable.id, order_type: "table" });
      const newRound = { order: res.data, items: [], roundNumber: 1 };
      setAllRounds([newRound]);
      setDraftRoundIdx(0);
      await loadData();
    } catch (err) {
      if (err.response?.data?.order_id) {
        await loadTableRounds(selectedTable);
      }
    }
    setRoundLoading(false);
  };

  const startNewRound = async () => {
    if (!selectedTable) return;
    const hasDraft = allRounds.some(r => r.order.status === "draft");
    if (hasDraft) return;
    setRoundLoading(true);
    try {
      const res = await API.post("/orders", {
        table_id: selectedTable.id,
        order_type: "table",
        addendum: true,
      });
      const newRound = { order: res.data, items: [], roundNumber: allRounds.length + 1 };
      setAllRounds(prev => [...prev, newRound]);
      setDraftRoundIdx(allRounds.length);
      setTimeout(() => {
        summaryRef.current?.scrollTo({ top: summaryRef.current.scrollHeight, behavior: "smooth" });
      }, 200);
    } catch {}
    setRoundLoading(false);
  };

  const startTakeaway = async () => {
    setRoundLoading(true);
    try {
      const res = await API.post("/orders", { order_type: "takeaway" });
      const newRound = { order: res.data, items: [], roundNumber: 1 };
      setAllRounds([newRound]);
      setDraftRoundIdx(0);
      setSelectedTable(null);
      setActiveOrderType("takeaway");
    } catch {}
    setRoundLoading(false);
    setView("order");
  };

  const addItem = async (menuItem) => {
    if (draftRoundIdx === null) return;
    const draftRound = allRounds[draftRoundIdx];
    if (!draftRound || draftRound.order.status !== "draft") return;

    const special = specials[menuItem.id];
    const unit_price = special ? special.discounted_price : menuItem.price;

    try {
      await API.post(`/orders/${draftRound.order.id}/items`, {
        menu_id: menuItem.id,
        quantity: 1,
        unit_price,
      });
      await refreshRound(draftRoundIdx);
    } catch {}
  };

  const removeItem = async (itemId) => {
    if (draftRoundIdx === null) return;
    const draftRound = allRounds[draftRoundIdx];
    if (!draftRound || draftRound.order.status !== "draft") return;
    try {
      await API.delete(`/orders/${draftRound.order.id}/items/${itemId}`);
      await refreshRound(draftRoundIdx);
    } catch {}
  };

  const handleSendToKitchen = async () => {
    if (draftRoundIdx === null) return;
    const draftRound = allRounds[draftRoundIdx];
    if (!draftRound || draftRound.items.length === 0) return;
    setConfirming(true);
    try {
      await API.put(`/orders/${draftRound.order.id}/confirm`);
      await refreshRound(draftRoundIdx);
      setDraftRoundIdx(null);
      setConfirmModal(false);
      await loadData();
    } catch {}
    setConfirming(false);
  };

  const handleLogout = async () => {
    try { await API.post("/auth/logout"); } catch {}
    logout(); navigate("/");
  };

  const goBack = () => {
    setView("tables");
    setAllRounds([]);
    setDraftRoundIdx(null);
    setSelectedTable(null);
    loadData();
  };

  const categories = [...new Set(menu.map(m => m.category))];
  const catIcons = { food: "🍛", drink: "🥤", dessert: "🍰", snack: "🍿" };
  const roundColors = ["#6366f1", "#10b981", "#f59e0b", "#ec4899"];
  const combinedTotal = allRounds.reduce((sum, r) => sum + Number(r.order?.total || 0), 0);

  return (
    <div style={{
      minHeight: "100vh",
      background: "radial-gradient(circle at top, #1e293b, #020617)",
      color: "#fff",
      display: "flex",
      flexDirection: "column"
    }}>

      {/* PREMIUM HEADER */}
      <header style={{
        ...glass,
        padding: "14px 24px",
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center"
      }}>
        <div style={{ fontWeight: 800, fontSize: 18 }}>
          🍽️ Waiter Panel
        </div>

        <div style={{ display: "flex", gap: 10 }}>
          <button onClick={toggleTheme} style={{ ...glass, padding: "8px 12px", borderRadius: 8 }}>
            {theme === "dark" ? "🌙" : "☀️"}
          </button>
          <button onClick={handleLogout} style={{ ...glass, padding: "8px 12px", borderRadius: 8 }}>
            🚪
          </button>
        </div>
      </header>

      <div style={{ flex: 1, padding: 20 }}>

        {view === "tables" && (
          <>
            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 20 }}>
              <h2 style={{ fontWeight: 800 }}>Tables</h2>
              <button onClick={startTakeaway} style={{
                background: "linear-gradient(135deg,#f59e0b,#d97706)",
                border: "none",
                padding: "10px 16px",
                borderRadius: 10,
                fontWeight: 700,
                color: "#fff",
                ...smooth
              }}>
                📦 Takeaway
              </button>
            </div>

            <div style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fill,minmax(140px,1fr))",
              gap: 16
            }}>
              {tables.map(t => (
                <div
                  key={t.id}
                  onClick={() => selectTable(t)}
                  style={{
                    ...glass,
                    ...smooth,
                    padding: 20,
                    borderRadius: 14,
                    cursor: "pointer",
                    textAlign: "center"
                  }}
                  onMouseEnter={e => e.currentTarget.style.transform = "translateY(-6px) scale(1.02)"}
                  onMouseLeave={e => e.currentTarget.style.transform = "none"}
                >
                  <div style={{ fontSize: 22, fontWeight: 800 }}>
                    T{t.table_number}
                  </div>
                  <div style={{ fontSize: 12, opacity: 0.7 }}>
                    {t.status}
                  </div>
                </div>
              ))}
            </div>
          </>
        )}

        {view === "order" && (
          <div style={{ display: "grid", gridTemplateColumns: "1fr 360px", gap: 20 }}>

            {/* MENU */}
            <div>
              {categories.map(cat => (
                <div key={cat} style={{ marginBottom: 24 }}>
                  <h3 style={{ marginBottom: 10 }}>
                    {catIcons[cat]} {cat}
                  </h3>

                  <div style={{
                    display: "grid",
                    gridTemplateColumns: "repeat(auto-fill,minmax(150px,1fr))",
                    gap: 12
                  }}>
                    {menu.filter(m => m.category === cat).map(item => (
                      <button
                        key={item.id}
                        onClick={() => addItem(item)}
                        style={{
                          ...glass,
                          ...smooth,
                          padding: 14,
                          borderRadius: 12,
                          textAlign: "left"
                        }}
                        onMouseEnter={e => e.currentTarget.style.transform = "translateY(-4px)"}
                        onMouseLeave={e => e.currentTarget.style.transform = "none"}
                      >
                        <div style={{ fontWeight: 700 }}>{item.name}</div>
                        <div style={{ opacity: 0.7 }}>Rs {item.price}</div>
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>

            {/* SUMMARY */}
            <div style={{ ...glass, borderRadius: 16, padding: 16 }}>
              <h3 style={{ marginBottom: 10 }}>🧾 Summary</h3>

              {allRounds.map((r, i) => (
                <div key={i} style={{ marginBottom: 12 }}>
                  <div style={{ fontWeight: 700 }}>Round {i + 1}</div>
                  {r.items.map(it => (
                    <div key={it.id} style={{ fontSize: 13, opacity: 0.8 }}>
                      {it.name} × {it.quantity}
                    </div>
                  ))}
                </div>
              ))}

              <hr style={{ opacity: 0.2 }} />

              <div style={{
                display: "flex",
                justifyContent: "space-between",
                fontWeight: 800
              }}>
                <span>Total</span>
                <span>Rs {combinedTotal}</span>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
